# 우도
import numpy as np
import matplotlib.pyplot as plt
data = np.array([1, 1, 1, 0, 1])  # 동전 던지기 - 데이터
# 정상적인 동전 분포 vs 앞면이 잘 나오는 찌그러진 동전 분포 확인
n_heads = np.sum(data == 1)  # 4
n_tails = np.sum(data == 0)  # 1
# 분포 우도를 구하는 식 : 이산적(1/2)
def calculate_likelihood(theta, heads, tails): # 확률은 곱셉원칙(독립적일 때의 확률)
  return (theta ** heads) * ((1 - theta) ** tails)
# 가설
theta_A = 0.5 # 정상 동전 분포일 것이다
theta_B = 0.8 # 찌그러진 동전을 던졌을 때의 분포일 것이다
lik_A = calculate_likelihood(theta_A, n_heads, n_tails)
lik_B = calculate_likelihood(theta_B, n_heads, n_tails)
print(f"가설 A (앞면 확률 50%): 우도(Likelihood) = {lik_A :.5f}")
print(f"가설 B (앞면 확률 80%): 우도(Likelihood) = {lik_B :.5f}")
print(f"-> 가설 B의 우도가 약 {lik_B/lik_A:.2f}배 더 높으므로, 현재 데이터에는 가설 B가 더 적합합니다.")
# 우도값은 최대 우도법

import scipy.stats as stats
# 생성 정규분포 확인( 표준편차 0.2 분포에서 생성)
errors = np.array([-0.5, 0.2, 0.1, -0.2]) # 정규분포 ( 평균, 표준편차)
# 가설(표준편차)
sigma_A = 0.2
sigma_B = 0.5
# 밀도함수
# 가설 A (오차 표준편차 0.2): 우도 = 0.22582 최대우도법
lik_sigma_A = np.prod(stats.norm.pdf(errors, loc = 0, scale = sigma_A))
lik_sigma_B = np.prod(stats.norm.pdf(errors, loc = 0, scale = sigma_B))

print(f" --- 연속형 오차 우도 결과 ---")
print(f" 가설 A (오차 표준편차 0.2): 우도 = {lik_sigma_A:.5f}")
print(f" 가설 B (오차 표준편차 0.5): 우도 = {lik_sigma_B:.5f}")

