# AIC나 BIC나 모델을 평가할 때는 작은 값이 우선

import numpy as np
import matplotlib.pyplot as plt
n_samples = np.arange(7, 500)
aic_penalty = 2 * np.ones_like(n_samples)
bic_penalty = np.log(n_samples)
# 시각화
plt.figure(figsize = (10, 5))
plt.plot(n_samples, aic_penalty, label = 'AIC penalty', color = 'royalblue', linewidth = 2)
plt.plot(n_samples, bic_penalty, label = 'BIC penalty', color = 'crimson', linewidth = 2)
plt.axvline(x = 7.38, color = 'gray', linestyle = '--', alpha = 0.7, label = 'ln(n) = 2( n ≈ 7.4)')
plt.title('AIC vs BIC', fontsize = 14)
plt.xlabel('Sample Size (n)', fontsize = 12)
plt.ylabel('Penalty Weight', fontsize = 12)
plt.legend(fontsize = 11)
plt.grid(True, linestyle = ':', alpha = 0.6)
plt.show()

import statsmodels.api as sm
import pandas as pd
# integrated (미분과 적분이 결합)
from statsmodels.tsa.arima.model import ARIMA
np.random.seed(42)
n = 150
eps = np.random.normal(0, 1, n) # epsilon 상수 : 부동소수점을 비교 (0.01 이하는 없는 수로 한다.)
y = np.zeros(n)
for t in range(2, n):
  # 시계열 데이터 생성식
  y[t] = 0.6 * y[t-1] - 0.3 * y[t-2] + eps[t]
results = []
for p in range(1, 6): # 1~5
  # 하나의 변수의 데이터 입력
  # p(AR), d(차분), q(MA)
  model = ARIMA(y, order = (p, 0, 0)).fit()
  results.append({
      'AR Order (p)': p,
      'AIC': model.aic, # 자동계산 (모델 평가 지표)
      'BIC': model.bic
  })
df_res = pd.DataFrame(results)
print("--- 모델 평가 결과 ---")
print(df_res.to_string(index = False))


# pandas에서 인덱스를 발견하는 함수 : idxmin
# numpy 에서 인덱스를 발견하는 함수 : argmin
# 문제 : 위 함수를 이용해서 가장 작은 차수를 출력하시오

df_res.loc[df_res['AIC'].idxmin(), 'AR Order (p)' ]

df_res.loc[df_res['BIC'].idxmin(), 'AR Order (p)' ]

# 차분과 적분(누적값)의 동일성 확인
y = pd.Series([100, 103, 107, 106, 110, 115, 117, 120], name = "original")
# 미분
diff_y = y.diff() # 차분
# 적분
recovered_y = diff_y.fillna(0).cumsum() + y.iloc[0] # 처음값을 더해줌
result = pd.DataFrame({
    "원본 y": y,
    "차분 diff(y)": diff_y,
    "누적복원 recovered": recovered_y
})
print(result)

print("\n원본과 복원값이 같은가?")
print(np.allclose(y, recovered_y))

# 정상성 검정
from statsmodels.tsa.stattools import adfuller
from statsmodels.tsa.stattools import kpss
def run_adf(series):
  result = adfuller(series) # 귀무가설 : 비정상이다.
  print(f"ADF Statistic : {result[0]:.4f}")
  print(f"p-value       : {result[1]:.4f}")
  if result[1] < 0.05:
    print("=> 정상성(Stationary) 가능")
  else:
    print("=> 비정상(Non-Stationary) 가능")
def run_kpss(series):
  result = kpss(series, regression = 'c', nlags = 'auto') # 귀무가설 : 정상이다.
  print(f"KPSS Statistic: {result[0]:.4f}")
  print(f"p-value       : {result[1]:.4f}")
  if result[1] < 0.05:
    print("=> 비정상(Non-Stationary) 가능")
  else:
    print("=> 정상성(Stationary) 가능")

np.random.seed(42)
n = 300
trend = np.linspace(0, 20, n)
random_walk = np.cumsum(np.random.normal(0, 1, n))
ts = trend + random_walk
ts = pd.Series(ts)
# 정상성 검정
run_adf(ts)   # 비정상
run_kpss(ts)  # 비정상
# 차분
diff_ts = ts.diff().dropna()
run_adf(diff_ts)  # 정상성
run_kpss(diff_ts) # 정상성

#ACF
from statsmodels.graphics.tsaplots import plot_acf
fig, axes = plt.subplots(1, 2, figsize = (14, 4))
plot_acf(ts, lags = 30, ax = axes[0])
axes[0].set_title("원본 ACF")
plot_acf(diff_ts, lags = 30, ax = axes[1])
axes[1].set_title("차분 후 ACF")
plt.show()

# 2차 차분
diff2_ts = diff_ts.diff().dropna()
run_adf(diff2_ts)
run_kpss(diff2_ts)

# 분산 비교
pd.DataFrame({ # 2차 차분 후 1차 보다 분산 증가
    "Series": ["Original", "1st Difference", "2nd Difference"],
    "Variance": [ts.var(), diff_ts.var(), diff2_ts.var()]
})

lag1_autocorr_diff1 = diff_ts.autocorr(lag = 1) # lag 별 자기상관
lag1_autocorr_diff2 = diff2_ts.autocorr(lag = 1)
lag1_autocorr_diff1 - lag1_autocorr_diff2 # 자기 상관 0.5이상 벌어지면 1차 차분만

# SARIMAX
from statsmodels.tsa.statespace.sarimax import SARIMAX
df = pd.read_csv('/content/drive/MyDrive/dataset/AirPassengers.csv', parse_dates = ['Month'], index_col = 'Month')
ts = df['AirPassengers']
ts

train = ts[:-24]
test = ts[-24:]

model = SARIMAX(train, order = (1, 1, 0), # AR(1lag 이전값), 차분(1차), MA(0은 고려하지 않고)
                seasonal_order = (1, 1, 1, 12), # AR(1), 차분, MA, 게절성 기간(12) 12개월 이전의 값을 반영할 것인가
                enforce_stationary = False, # 비정상 -> 정상성
                enforce_invertibility = False, # 가역성 -> 이전 오차 -> 줄여서 반영
                trend = 'c') # c: constant 상수(시간에 따라 일정), t: 시간에 따라 트렌드 변화, ct: 둘 다 고려
results = model.fit()
print(results.summary())

# 예측
pred = results.get_forecast(steps = 36)
pred_ci = pred.conf_int()  # 신뢰구간 계산
plt.figure(figsize = (12, 6))
plt.plot(train, label = "Train")
plt.plot(test, label = "Test", color = "gray") # 검증용
plt.plot(pred.predicted_mean, label = "Predicted", color = "red") # 예측한 값
plt.fill_between(pred_ci.index, pred_ci.iloc[:,0], pred_ci.iloc[:,1], color = "pink", alpha = 0.3)
plt.title("SARIMA 예측 (AirPassengers)")
plt.legend()
plt.show()

# L1에 표시된 값 lags = [1]
results.test_serial_correlation(method = 'ljungbox', lags = [1])

# 등분산성
results.test_heteroskedasticity(method = 'breakvar')

