# 자동 차수 결정
import itertools
p = d = q = range(0, 3)
pdq = list(itertools.product(p, d, q))
seasonal_pdq = [(x[0], x[1], x[2], 12) for x in pdq]

best_aic = float("inf")
best_order = None
best_seasonal_order = None
best_model = None

for order in pdq:
  for seasonal_order in seasonal_pdq:
    try:
      model = SARIMAX(ts, order = order, seasonal_order = seasonal_order, enforce_stationary = False, enforce_invertibility = False)
      results = model.fit(disp = False)
      if results.aic < best_aic:
        best_aic = results.aic
        best_order = order
        best_seasonal_order = seasonal_order
        best_model = results
    except:
      continue

best_order

best_seasonal_order

best_aic

print(best_model.summary())

pred = results.get_forecast(steps = 36)
pred_ci = pred.conf_int()  # 신뢰구간 계산
plt.figure(figsize = (12, 6))
plt.plot(train, label = "Train")
plt.plot(test, label = "Test", color = "gray") # 검증용
plt.plot(pred.predicted_mean, label = "Predicted", color = "red") # 예측한 값
plt.fill_between(pred_ci.index, pred_ci.iloc[:,0], pred_ci.iloc[:,1], color = "pink", alpha = 0.3)
plt.title("SARIMA 예측 (AirPassengers)")
plt.legend()
plt.show()